  * All Rights Reserved.
  * Contributor(s): Openbravo SLU
  * Contributions are Copyright (C) 2001-2016 Openbravo, S.L.U.
  *
  * Specifically, this derivative work is based upon the following Compiere
  * file and version.
  *************************************************************************
  * $Id: cscm_deletelines.sql,v 1.6 2003/05/26 22:31:16 jjanke Exp $
  ***
  * Title: Create Asset and Delivery
  * Description:
  * Open Issues:
  * - Reversal or Negative Delivery
  * - Guarantee Extension
  ************************************************************************/
  -- Logistice
  v_ResultStr VARCHAR2(2000):='';
  v_Message VARCHAR2(2000):='';
  v_Result NUMBER:=1; -- 0=failure
  v_Record_ID VARCHAR2(32);
  v_AD_User_ID VARCHAR2(32);
  -- Parameter
  TYPE RECORD IS REF CURSOR;
    Cur_Parameter RECORD;
    -- Parameter Variables
    -- Create from ShipmentLine
    Cur_ShipLine RECORD;
    --
    v_A_Asset_ID VARCHAR2(32) ;
    v_C_OrderLine_ID VARCHAR2(32) ;
    v_DocumentNo VARCHAR2(40) ;
    v_Value VARCHAR2(60) ;
    v_Name VARCHAR2(80) ;
    v_count NUMBER:=0;
    v_Asset_Value VARCHAR2(200) ;
    v_cscm_delforecastrel VARCHAR(2);
  BEGIN
    --  Update AD_PInstance
    IF(p_PInstance_ID IS NOT NULL) THEN
      DBMS_OUTPUT.PUT_LINE('cscm_deletelines - Processing ' || p_PInstance_ID) ;
      v_ResultStr:='PInstanceNotFound';
      AD_UPDATE_PINSTANCE(p_PInstance_ID, NULL, 'Y', NULL, NULL) ;
      -- Get Parameters
      v_ResultStr:='ReadingParameters';
      FOR Cur_Parameter IN
        (SELECT i.Record_ID, i.AD_User_ID, p.ParameterName, p.P_String, p.P_Number, p.P_Date
        FROM AD_PInstance i
        LEFT JOIN AD_PInstance_Para p
          ON i.AD_PInstance_ID=p.AD_PInstance_ID
        WHERE i.AD_PInstance_ID=p_PInstance_ID
        ORDER BY p.SeqNo
        )
      LOOP
        v_Record_ID:=Cur_Parameter.Record_ID;
        v_AD_User_ID:=Cur_Parameter.AD_User_ID;
	IF (Cur_Parameter.ParameterName = 'C_OrderLine_ID') THEN
		v_C_OrderLine_ID := Cur_Parameter.P_String;
        end if;
	IF (Cur_Parameter.ParameterName = 'cscm_delforecastrel') THEN
		v_cscm_delforecastrel := Cur_Parameter.P_String;
        end if;
      END LOOP; -- Get Parameter


	DELETE FROM MRP_RUN_PURCHASELINE WHERE MRP_RUN_PURCHASE_ID = v_Record_ID and (v_C_OrderLine_ID is null or 
			(MRP_RUN_PURCHASELINE.C_OrderLine_ID in (select C_OrderLine_ID from C_OrderLine where C_Order_ID=(select C_Order_ID from C_OrderLine where C_OrderLine_ID=v_C_OrderLine_ID)) 
			and (select count(*) from C_OrderLine col inner join c_order co on co.c_order_id = col.c_order_id where C_OrderLine_id = v_C_OrderLine_ID and co.docstatus = 'DR')>0
			)) and 
	((v_cscm_delforecastrel = 'Y' and mrp_salesforecastline_id is not null) or v_cscm_delforecastrel = 'N');

    END IF;
  BEGIN --BODY

    IF(p_PInstance_ID IS NOT NULL) THEN
      AD_UPDATE_PINSTANCE(p_PInstance_ID, NULL, 'N', v_Result, v_Message) ;
    END IF;
    RETURN;
  END; --BODY
EXCEPTION
WHEN OTHERS THEN
  v_ResultStr:= '@ERROR=' || SQLERRM;
  DBMS_OUTPUT.PUT_LINE(v_ResultStr) ;
  ROLLBACK;
  IF(p_PInstance_ID IS NOT NULL) THEN
    AD_UPDATE_PINSTANCE(p_PInstance_ID, NULL, 'N', 0, v_ResultStr) ;
  END IF;
  RETURN;
END CSCM_DELETELINES
